import fs from "fs";
import path from "path";
import type { SignedArticle, ContentManifest, SectionSlug } from "./types";

// In production, this reads from the pre-signed manifest generated by the seed script.
// During development without signed content, it falls back to placeholder data.
let _manifest: ContentManifest | null = null;

function loadManifest(): ContentManifest {
  if (_manifest) return _manifest;

  try {
    const manifestPath = path.join(
      process.cwd(),
      "public",
      "signed-content",
      "manifest.json"
    );
    const raw = fs.readFileSync(manifestPath, "utf-8");
    _manifest = JSON.parse(raw) as ContentManifest;
  } catch {
    // Fallback: use placeholder articles for development
    _manifest = getPlaceholderManifest();
  }

  return _manifest;
}

export function getAllArticles(): SignedArticle[] {
  return loadManifest().articles;
}

export function getArticleBySlug(slug: string): SignedArticle | undefined {
  return getAllArticles().find((a) => a.slug === slug);
}

export function getArticlesBySection(section: SectionSlug): SignedArticle[] {
  return getAllArticles().filter((a) => a.section === section);
}

export function getFeaturedArticle(): SignedArticle | undefined {
  return getAllArticles().find((a) => a.featured);
}

export function getAllSlugs(): string[] {
  return getAllArticles().map((a) => a.slug);
}

export function getManifest(): ContentManifest {
  return loadManifest();
}

